  11	/**
  12	 * Truncates a string to a specified maximum length, appending a suffix if truncated.
  13	 *
  14	 * If the input string is shorter than or equal to the maximum length, it is returned as-is.
  15	 * Otherwise, it is trimmed so that the result (including the suffix) fits within the length.
  16	 *
  17	 * @param input - The string to truncate.
  18	 * @param options - Optional configuration.
  19	 * @returns The truncated string.
  20	 *
  21	 * @example
  22	 * ```ts
  23	 * truncate('Hello, World!', { length: 10 }) // 'Hello, ...',
  24	 * truncate('Short')                         // 'Short'
  25	 * truncate('Hello, World!', { length: 10, suffix: '…' }) // 'Hello, Wo…'
  26	 * ```
  27	 */
  28	export function truncate(input: string, options: TruncateOptions = {}): string {
  29	  const { length = 30, suffix = '...' } = options;
  30	
  31	  if (input.length <= length) {
  32	    return input;
  33	  }
  34	
  35	  const trimLength = length - suffix.length;
  36	
  37	  if (trimLength <= 0) {
  38	    return suffix.slice(0, length);
  39	  }
  40	
  41	  return input.slice(0, trimLength) + suffix;
  42	}
