582	/* Like sdscatprintf() but gets va_list instead of being variadic. */
583	sds sdscatvprintf(sds s, const char *fmt, va_list ap) {
584	    va_list cpy;
585	    char staticbuf[1024], *buf = staticbuf, *t;
586	    size_t buflen = strlen(fmt)*2;
587	    int bufstrlen;
588	
589	    /* We try to start using a static buffer for speed.
590	     * If not possible we revert to heap allocation. */
591	    if (buflen > sizeof(staticbuf)) {
592	        buf = s_malloc(buflen);
593	        if (buf == NULL) return NULL;
594	    } else {
595	        buflen = sizeof(staticbuf);
596	    }
597	
598	    /* Alloc enough space for buffer and \0 after failing to
599	     * fit the string in the current buffer size. */
600	    while(1) {
601	        va_copy(cpy,ap);
602	        bufstrlen = vsnprintf(buf, buflen, fmt, cpy);
603	        va_end(cpy);
604	        if (bufstrlen < 0) {
605	            if (buf != staticbuf) s_free(buf);
606	            return NULL;
607	        }
608	        if (((size_t)bufstrlen) >= buflen) {
609	            if (buf != staticbuf) s_free(buf);
610	            buflen = ((size_t)bufstrlen) + 1;
611	            buf = s_malloc(buflen);
612	            if (buf == NULL) return NULL;
613	            continue;
614	        }
615	        break;
616	    }
617	
618	    /* Finally concat the obtained string to the SDS string and return it. */
619	    t = sdscatlen(s, buf, bufstrlen);
620	    if (buf != staticbuf) s_free(buf);
621	    return t;
622	}
623	
624	/* Append to the sds string 's' a string obtained using printf-alike format
625	 * specifier.
626	 *
627	 * After the call, the modified sds string is no longer valid and all the
628	 * references must be substituted with the new pointer returned by the call.
629	 *
630	 * Example:
631	 *
632	 * s = sdsnew("Sum is: ");
633	 * s = sdscatprintf(s,"%d+%d = %d",a,b,a+b).
634	 *
635	 * Often you need to create a string from scratch with the printf-alike
636	 * format. When this is the need, just use sdsempty() as the target string:
637	 *
638	 * s = sdscatprintf(sdsempty(), "... your format ...", args);
639	 */
640	sds sdscatprintf(sds s, const char *fmt, ...) {
641	    va_list ap;
642	    char *t;
643	    va_start(ap, fmt);
644	    t = sdscatvprintf(s,fmt,ap);
645	    va_end(ap);
646	    return t;
647	}

